  -- ---- Assign the test to every existing student ----
  insert into public.test_assignments (test_id, student_id)
  select v_test_id, p.id
  from public.profiles p
  where p.role = 'student'
  on conflict (test_id, student_id) do nothing;

  raise notice 'Created SAT Practice Test A (%) with 98 questions and assigned it to all students.', v_test_id;
end $$;
